import React, { useState } from 'react';

interface Card {
  id: number;
  title: string;
  component: React.ReactNode;
  code: string;
  style: string;
}

const cards: Card[] = [
  {
    id: 1,
    title: 'Simple Button',
    component: (
      <button style={{
        padding: '10px 20px',
        backgroundColor: '#61dafb',
        color: '#282c34',
        border: 'none',
        borderRadius: '4px',
        cursor: 'pointer',
        fontSize: '16px'
      }}>
        Click Me
      </button>
    ),
    code: `const Button = () => {\n  return (\n    <button style={{\n      padding: '10px 20px',\n      backgroundColor: '#61dafb',\n      color: '#282c34',\n      border: 'none',\n      borderRadius: '4px',\n      cursor: 'pointer',\n      fontSize: '16px'\n    }}>\n      Click Me\n    </button>\n  );\n};`,
    style: `.button {\n  padding: 10px 20px;\n  background-color: #61dafb;\n  color: #282c34;\n  border: none;\n  border-radius: 4px;\n  cursor: pointer;\n  font-size: 16px;\n}`,
  },
  {
    id: 2,
    title: 'Input Field',
    component: (
      <input
        type="text"
        placeholder="Enter text..."
        style={{
          padding: '10px',
          border: '2px solid #61dafb',
          borderRadius: '4px',
          fontSize: '16px',
          width: '100%',
          boxSizing: 'border-box',
          backgroundColor: '#f7f7f7',
          color: '#282c34'
        }}
      />
    ),
    code: `const Input = () => {\n  return (\n    <input\n      type="text"\n      placeholder="Enter text..."\n      style={{\n        padding: '10px',\n        border: '2px solid #61dafb',\n        borderRadius: '4px',\n        fontSize: '16px',\n        width: '100%',\n        boxSizing: 'border-box',\n        backgroundColor: '#f7f7f7',\n        color: '#282c34'\n      }}\n    />\n  );\n};`,
    style: `.input {\n  padding: 10px;\n  border: 2px solid #61dafb;\n  border-radius: 4px;\n  font-size: 16px;\n  width: 100%;\n  box-sizing: border-box;\n  background-color: #f7f7f7;\n  color: #282c34;\n}`,
  },
  // Add more cards as needed
];

const GridCards: React.FC = () => {
  const [selectedCard, setSelectedCard] = useState<Card | null>(null);
  const [activeTab, setActiveTab] = useState<'code' | 'style'>('code');

  const openModal = (card: Card) => {
    setSelectedCard(card);
    setActiveTab('code');
  };

  const closeModal = () => {
    setSelectedCard(null);
  };

  return (
    <div style={{ color: '#282c34' }}>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '30px', maxWidth: '1200px', margin: '0 auto' }}>
        {cards.map((card) => (
          <div
            key={card.id}
            onClick={() => openModal(card)}
            style={{
              backgroundColor: '#ffffff',
              border: '1px solid rgba(40, 44, 52, 0.12)',
              overflow: 'hidden',
              cursor: 'pointer',
              transition: 'all 0.2s ease',
              boxShadow: '0 2px 8px rgba(40, 44, 52, 0.08)',
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.backgroundColor = '#fafbfc';
              e.currentTarget.style.boxShadow = '0 4px 16px rgba(40, 44, 52, 0.12)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.backgroundColor = '#ffffff';
              e.currentTarget.style.boxShadow = '0 2px 8px rgba(40, 44, 52, 0.08)';
            }}
          >
            <div style={{
              height: '200px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              padding: '20px',
              backgroundColor: '#f7f7f7'
            }}>
              {card.component}
            </div>
            <div style={{ padding: '20px' }}>
              <h3 style={{ margin: 0, fontSize: '18px', fontWeight: '500', color: '#282c34' }}>{card.title}</h3>
            </div>
          </div>
        ))}
      </div>

      {selectedCard && (
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(245, 247, 251, 0.9)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 1000,
          }}
          onClick={closeModal}
        >
          <div
            style={{
              backgroundColor: '#ffffff',
              width: '90%',
              maxWidth: '700px',
              maxHeight: '90%',
              overflow: 'auto',
              border: '1px solid rgba(40, 44, 52, 0.16)',
              boxShadow: '0 16px 40px rgba(40, 44, 52, 0.12)',
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '30px 30px 20px 30px', borderBottom: '1px solid rgba(40, 44, 52, 0.12)', backgroundColor: '#f7f7f7' }}>
              <h2 style={{ margin: 0, fontSize: '24px', fontWeight: '400', color: '#282c34' }}>{selectedCard.title}</h2>
              <button onClick={closeModal} style={{ background: 'none', border: 'none', fontSize: '24px', cursor: 'pointer', color: '#282c34', padding: '5px' }}>×</button>
            </div>
            <div style={{ display: 'flex', padding: '0 30px', borderBottom: '1px solid rgba(40, 44, 52, 0.12)', backgroundColor: '#f7f7f7' }}>
              <button
                onClick={() => setActiveTab('code')}
                style={{
                  padding: '15px 25px',
                  border: 'none',
                  backgroundColor: activeTab === 'code' ? '#61dafb' : 'transparent',
                  color: activeTab === 'code' ? '#282c34' : '#666',
                  cursor: 'pointer',
                  fontSize: '16px',
                  fontWeight: '500',
                  borderBottom: activeTab === 'code' ? '3px solid #282c34' : 'none',
                }}
              >
                JavaScript
              </button>
              <button
                onClick={() => setActiveTab('style')}
                style={{
                  padding: '15px 25px',
                  border: 'none',
                  backgroundColor: activeTab === 'style' ? '#61dafb' : 'transparent',
                  color: activeTab === 'style' ? '#282c34' : '#666',
                  cursor: 'pointer',
                  fontSize: '16px',
                  fontWeight: '500',
                  borderBottom: activeTab === 'style' ? '3px solid #282c34' : 'none',
                }}
              >
                CSS
              </button>
            </div>
            <div style={{
              padding: '30px',
              fontFamily: 'Monaco, Menlo, "Ubuntu Mono", monospace',
              fontSize: '14px',
              lineHeight: '1.5',
              backgroundColor: '#f7f7f7',
              color: '#282c34',
              overflow: 'auto'
            }}>
              <pre style={{ margin: 0, whiteSpace: 'pre-wrap' }}>
                <code style={{
                  color: '#282c34',
                }}>
                  {activeTab === 'code' ? selectedCard.code : selectedCard.style}
                </code>
              </pre>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default GridCards;